#include<bits/stdc++.h>
using namespace std;
struct segment_tree
{
	struct node
	{
		long long l,r,sum;
		long long lson,rson;
		long long tag;
		node():tag(-1){}
	}a[600010];
	long long cnt;
	segment_tree():cnt(0){}
	void pushup(long long x)
	{
		a[x].sum=(a[a[x].lson].sum+a[a[x].rson].sum);
	}
	void pushdown(long long x)
	{
		long long mid=(a[x].l+a[x].r)>>1;
		long long ls=a[x].lson,rs=a[x].rson;
		long long tg=a[x].tag;
        if(tg==-1)
        {
            return;
        }
		a[ls].sum=(mid-a[x].l+1)*tg;
		a[rs].sum=(a[x].r-mid)*tg;
		a[ls].tag=tg;
		a[rs].tag=tg;
		a[x].tag=-1;
	}
	long long init(long long l,long long r)
	{
		long long x=++cnt,mid=(l+r)>>1;
		a[x].l=l;
		a[x].r=r;
		if(l==r)
		{
			a[x].sum=0;
			return x;
		}
		a[x].lson=init(l,mid);
		a[x].rson=init(mid+1,r);
		pushup(x);
		return x;
	}
	void update(long long x,long long l,long long r,long long z)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return;
		}
		if(l<=a[x].l&&a[x].r<=r)
		{
			a[x].sum=((a[x].r-a[x].l+1)*z);
			a[x].tag=z;
			return;
		}
		pushdown(x);
		update(a[x].lson,l,r,z);
		update(a[x].rson,l,r,z);
		pushup(x);
	}
	long long getsum(long long x,long long l,long long r)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return 0;
		}
		if(a[x].l>=l&&a[x].r<=r)
		{
			return a[x].sum;
		}
		pushdown(x);
		return (getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r));
	}
}s;
int dp[100010][2];
int c[100010][2];
struct node
{
    int h,l,r,l1,r1,id;
    bool operator<(const node&b)const
    {
        return h<b.h;
    }
}a[100010];
int b[400010];
int main()
{
    int n,h;
    scanf("%d%d",&n,&h);
    int x,y;
    scanf("%d%d",&x,&y);
    n++;
    a[n].l=a[n].r=a[n].l1=a[n].r1=x;
    a[n].h=y;
    a[n].id=n;
    int tot=0;
    b[++tot]=x;
    for(int i=1;i<n;i++)
    {
        scanf("%d%d%d",&a[i].h,&a[i].l,&a[i].r);
        a[i].l1=a[i].l;
        a[i].r1=a[i].r;
        a[i].id=i;
        b[++tot]=a[i].l;
        b[++tot]=a[i].r;
    }
    sort(a+1,a+1+n);
    sort(b+1,b+1+tot);
    for(int i=1;i<=n;i++)
    {
        a[i].l1=lower_bound(b+1,b+1+tot,a[i].l)-b;
        a[i].r1=lower_bound(b+1,b+1+tot,a[i].r)-b;
    }
    s.init(1,tot);
    for(int i=1;i<=n;i++)
    {
        c[i][0]=s.getsum(1,a[i].l1,a[i].l1);
        c[i][1]=s.getsum(1,a[i].r1,a[i].r1);
        s.update(1,a[i].l1,a[i].r1,i);
    }
    memset(dp,0x3f,sizeof(dp));
    dp[0][0]=dp[0][1]=0;
    for(int i=1;i<=n;i++)
    {
        int ls=c[i][0],rs=c[i][1];
        if(a[i].h-a[ls].h<=h)
        {
            if(ls!=0)
            {
                dp[i][0]=min({dp[ls][0]+a[i].l-a[ls].l+a[i].h-a[ls].h,dp[ls][1]+a[ls].r-a[i].l+a[i].h-a[ls].h});
            }
            else
            {
                dp[i][0]=a[i].h;
            }
        }
        if(a[i].h-a[rs].h<=h)
        {
            if(rs!=0)
            {
                dp[i][1]=min({dp[rs][0]+a[i].r-a[rs].l+a[i].h-a[rs].h,dp[rs][1]+a[rs].r-a[i].r+a[i].h-a[rs].h});
            }
            else
            {
                dp[i][1]=a[i].h;
            }
        }
    }
    printf("%d",min(dp[n][0],dp[n][1]));
    return 0;
}
